content.content:
     1→/* ========== HERO ========== */
     2→.landing__hero {
     3→  position: relative;
     4→  min-height: 100vh;
     5→  display: flex;
     6→  align-items: center;
     7→  overflow: hidden;
     8→  padding: 8rem 0 4rem;
     9→}
    10→
    11→.landing__hero .container {
    12→  display: grid;
    13→  grid-template-columns: 1fr 1fr;
    14→  gap: 4rem;
    15→  align-items: center;
    16→  width: 100%;
    17→}
    18→
    19→/* Background */
    20→.landing__hero-bg {
    21→  position: absolute;
    22→  inset: 0;
    23→  pointer-events: none;
    24→  overflow: hidden;
    25→}
    26→
    27→.landing__orb {
    28→  position: absolute;
    29→  border-radius: 50%;
    30→  filter: blur(80px);
    31→  opacity: 0.12;
    32→}
    33→
    34→.landing__orb-1 {
    35→  width: 600px; height: 600px;
    36→  background: radial-gradient(circle, #6366f1, transparent 70%);
    37→  top: -200px; left: -200px;
    38→  animation: float-orb 12s ease-in-out infinite;
    39→}
    40→
    41→.landing__orb-2 {
    42→  width: 400px; height: 400px;
    43→  background: radial-gradient(circle, #8b5cf6, transparent 70%);
    44→  bottom: -100px; right: 10%;
    45→  animation: float-orb 15s ease-in-out infinite reverse;
    46→}
    47→
    48→.landing__orb-3 {
    49→  width: 300px; height: 300px;
    50→  background: radial-gradient(circle, #06b6d4, transparent 70%);
    51→  top: 40%; right: 30%;
    52→  animation: float-orb 10s ease-in-out infinite 3s;
    53→}
    54→
    55→@keyframes float-orb {
    56→  0%, 100% { transform: translate(0, 0) scale(1); }
    57→  33% { transform: translate(30px, -20px) scale(1.05); }
    58→  66% { transform: translate(-20px, 30px) scale(0.95); }
    59→}
    60→
    61→.landing__grid-pattern {
    62→  position: absolute;
    63→  inset: 0;
    64→  background-image:
    65→    linear-gradient(rgba(99,102,241,0.04) 1px, transparent 1px),
    66→    linear-gradient(90deg, rgba(99,102,241,0.04) 1px, transparent 1px);
    67→  background-size: 48px 48px;
    68→  mask-image: radial-gradient(ellipse 80% 80% at 50% 50%, black, transparent);
    69→}
    70→
    71→/* Hero content */
    72→.landing__hero-content {
    73→  display: flex;
    74→  flex-direction: column;
    75→  gap: 1.5rem;
    76→  z-index: 1;
    77→}
    78→
    79→.landing__hero-badge {
    80→  display: inline-flex;
    81→  align-items: center;
    82→  gap: 0.5rem;
    83→  padding: 0.4rem 1rem;
    84→  border-radius: 100px;
    85→  background: rgba(99,102,241,0.1);
    86→  border: 1px solid rgba(99,102,241,0.25);
    87→  color: #a5b4fc;
    88→  font-size: 0.82rem;
    89→  font-weight: 600;
    90→  letter-spacing: 0.04em;
    91→}
    92→
    93→.landing__hero-title {
    94→  font-size: clamp(2.4rem, 5vw, 4rem);
    95→  font-weight: 900;
    96→  line-height: 1.1;
    97→  letter-spacing: -0.04em;
    98→}
    99→
   100→.landing__hero-subtitle {
   101→  font-size: 1.1rem;
   102→  line-height: 1.7;
   103→  max-width: 500px;
   104→  color: var(--text-secondary);
   105→}
   106→
   107→.landing__hero-actions {
   108→  display: flex;
   109→  gap: 1rem;
   110→  flex-wrap: wrap;
   111→}
   112→
   113→.landing__cta-btn {
   114→  position: relative;
   115→  overflow: hidden;
   116→}
   117→
   118→.landing__cta-btn::before {
   119→  content: '';
   120→  position: absolute;
   121→  top: 0; left: -100%;
   122→  width: 100%; height: 100%;
   123→  background: linear-gradient(90deg, transparent, rgba(255,255,255,0.15), transparent);
   124→  transition: left 0.5s ease;
   125→}
   126→
   127→.landing__cta-btn:hover::before { left: 100%; }
   128→
   129→.landing__cta-arrow {
   130→  transition: transform 0.2s ease;
   131→}
   132→
   133→.landing__cta-btn:hover .landing__cta-arrow {
   134→  transform: translateX(4px);
   135→}
   136→
   137→.landing__hero-social-proof {
   138→  display: flex;
   139→  align-items: center;
   140→  gap: 0.75rem;
   141→  font-size: 0.875rem;
   142→  color: var(--text-muted);
   143→}
   144→
   145→.landing__hero-social-proof strong { color: var(--text-secondary); }
   146→
   147→.landing__avatars {
   148→  display: flex;
   149→}
   150→
   151→.landing__avatar {
   152→  width: 28px; height: 28px;
   153→  border-radius: 50%;
   154→  background: var(--gradient-primary);
   155→  border: 2px solid var(--bg-base);
   156→  display: flex;
   157→  align-items: center;
   158→  justify-content: center;
   159→  font-size: 0.65rem;
   160→  font-weight: 700;
   161→  color: white;
   162→  margin-left: -8px;
   163→}
   164→
   165→.landing__avatar:first-child { margin-left: 0; }
   166→
   167→/* Preview window */
   168→.landing__hero-preview {
   169→  z-index: 1;
   170→}
   171→
   172→.landing__preview-window {
   173→  background: var(--bg-surface);
   174→  border: 1px solid var(--border-color);
   175→  border-radius: 16px;
   176→  overflow: hidden;
   177→  box-shadow: var(--shadow-lg), 0 0 80px rgba(99,102,241,0.1);
   178→}
   179→
   180→.landing__preview-header {
   181→  background: var(--bg-surface-2);
   182→  border-bottom: 1px solid var(--border-color);
   183→  padding: 0.75rem 1rem;
   184→  display: flex;
   185→  align-items: center;
   186→  gap: 1rem;
   187→}
   188→
   189→.landing__preview-dots {
   190→  display: flex;
   191→  gap: 6px;
   192→}
   193→
   194→.landing__preview-dots span {
   195→  width: 10px; height: 10px;
   196→  border-radius: 50%;
   197→  background: var(--text-muted);
   198→  opacity: 0.4;
   199→}
   200→
   201→.landing__preview-title {
   202→  font-size: 0.78rem;
   203→  color: var(--text-muted);
   204→  font-weight: 500;
   205→}
   206→
   207→.landing__preview-body {
   208→  display: grid;
   209→  grid-template-columns: 160px 1fr;
   210→  height: 320px;
   211→}
   212→
   213→.landing__preview-sidebar {
   214→  border-right: 1px solid var(--border-color);
   215→  padding: 0.75rem;
   216→  display: flex;
   217→  flex-direction: column;
   218→  gap: 0.25rem;
   219→}
   220→
   221→.landing__preview-cat {
   222→  padding: 0.5rem 0.75rem;
   223→  border-radius: 8px;
   224→  font-size: 0.72rem;
   225→  color: var(--text-muted);
   226→  cursor: default;
   227→  transition: background 0.4s ease, color 0.4s ease;
   228→}
   229→
   230→.landing__preview-cat.active {
   231→  background: rgba(99,102,241,0.15);
   232→  color: var(--color-primary-light);
   233→  font-weight: 600;
   234→}
   235→
   236→/* ── Generating indicator ── */
   237→.preview-generating {
   238→  display: flex;
   239→  align-items: center;
   240→  gap: 4px;
   241→  margin-top: 0.75rem;
   242→}
   243→
   244→.preview-dot {
   245→  width: 5px;
   246→  height: 5px;
   247→  border-radius: 50%;
   248→  background: var(--color-primary);
   249→  opacity: 0.6;
   250→  animation: preview-bounce 1.1s ease-in-out infinite;
   251→}
   252→
   253→@keyframes preview-bounce {
   254→  0%, 100% { transform: translateY(0);    opacity: 0.35; }
   255→  50%       { transform: translateY(-4px); opacity: 1;    }
   256→}
   257→
   258→.preview-generating-text {
   259→  font-size: 0.65rem;
   260→  color: var(--text-muted);
   261→  margin-left: 4px;
   262→  animation: preview-blink 2s ease-in-out infinite;
   263→}
   264→
   265→@keyframes preview-blink {
   266→  0%, 100% { opacity: 0.35; }
   267→  50%       { opacity: 0.8;  }
   268→}
   269→
   270→.landing__preview-main {
   271→  padding: 1rem;
   272→  overflow: hidden;
   273→}
   274→
   275→.landing__preview-tool-header {
   276→  font-size: 0.82rem;
   277→  font-weight: 700;
   278→  color: var(--text-primary);
   279→  margin-bottom: 0.75rem;
   280→}
   281→
   282→.landing__preview-label {
   283→  font-size: 0.68rem;
   284→  color: var(--text-muted);
   285→  text-transform: uppercase;
   286→  letter-spacing: 0.06em;
   287→  margin-bottom: 0.25rem;
   288→}
   289→
   290→.landing__preview-value {
   291→  background: var(--bg-surface-2);
   292→  border: 1px solid var(--border-color);
   293→  border-radius: 6px;
   294→  padding: 0.4rem 0.75rem;
   295→  font-size: 0.78rem;
   296→  color: var(--text-secondary);
   297→  margin-bottom: 1rem;
   298→}
   299→
   300→.landing__preview-output {
   301→  display: flex;
   302→  flex-direction: column;
   303→  gap: 0.5rem;
   304→}
   305→
   306→.landing__preview-line {
   307→  height: 10px;
   308→  background: linear-gradient(90deg, var(--bg-surface-2), var(--bg-surface-3));
   309→  border-radius: 4px;
   310→  animation: shimmer 2s ease infinite;
   311→}
   312→
   313→@keyframes shimmer {
   314→  0% { opacity: 0.4; }
   315→  50% { opacity: 0.8; }
   316→  100% { opacity: 0.4; }
   317→}
   318→
   319→/* ========== STATS ========== */
   320→.landing__stats {
   321→  padding: 3rem 0;
   322→  background: var(--bg-surface);
   323→  border-top: 1px solid var(--border-color);
   324→  border-bottom: 1px solid var(--border-color);
   325→}
   326→
   327→.landing__stats-grid {
   328→  display: grid;
   329→  grid-template-columns: repeat(4, 1fr);
   330→  gap: 2rem;
   331→  text-align: center;
   332→}
   333→
   334→.landing__stat-value {
   335→  font-size: 2.5rem;
   336→  font-weight: 900;
   337→  letter-spacing: -0.04em;
   338→  line-height: 1;
   339→  margin-bottom: 0.5rem;
   340→}
   341→
   342→.landing__stat-value span { font-size: inherit; }
   343→
   344→.landing__stat-label {
   345→  font-size: 0.875rem;
   346→  color: var(--text-muted);
   347→  font-weight: 500;
   348→}
   349→
   350→/* ========== CATEGORIES ========== */
   351→.landing__badge-wrap { text-align: center; }
   352→
   353→.landing__categories-grid {
   354→  display: grid;
   355→  grid-template-columns: repeat(4, 1fr);
   356→  gap: 1.25rem;
   357→}
   358→
   359→.landing__category-card {
   360→  background: var(--bg-card);
   361→  border: 1px solid var(--border-color);
   362→  border-radius: var(--border-radius-lg);
   363→  padding: 1.5rem;
   364→  cursor: default;
   365→  transition: all var(--transition);
   366→  display: flex;
   367→  flex-direction: column;
   368→  gap: 0.75rem;
   369→}
   370→
   371→.landing__category-card:hover {
   372→  border-color: var(--border-hover);
   373→  background: var(--bg-card-hover);
   374→  box-shadow: var(--shadow-glow);
   375→}
   376→
   377→.landing__category-icon {
   378→  width: 48px; height: 48px;
   379→  border-radius: 12px;
   380→  border: 1px solid;
   381→  display: flex;
   382→  align-items: center;
   383→  justify-content: center;
   384→  font-size: 1.5rem;
   385→}
   386→
   387→.landing__category-name {
   388→  font-size: 1rem;
   389→  font-weight: 700;
   390→  color: var(--text-primary);
   391→}
   392→
   393→.landing__category-desc {
   394→  font-size: 0.8rem;
   395→  color: var(--text-muted);
   396→  line-height: 1.5;
   397→}
   398→
   399→.landing__category-tools {
   400→  display: flex;
   401→  flex-wrap: wrap;
   402→  gap: 0.4rem;
   403→  margin-top: auto;
   404→}
   405→
   406→.landing__tool-tag {
   407→  font-size: 0.72rem;
   408→  padding: 0.2rem 0.6rem;
   409→  background: var(--bg-surface-2);
   410→  border: 1px solid var(--border-color);
   411→  border-radius: 100px;
   412→  color: var(--text-muted);
   413→}
   414→
   415→.landing__tool-tag--more {
   416→  color: var(--color-primary-light);
   417→  border-color: rgba(99,102,241,0.2);
   418→  background: rgba(99,102,241,0.05);
   419→}
   420→
   421→/* ========== FEATURES ========== */
   422→.landing__feature-card {
   423→  background: var(--bg-card);
   424→  border: 1px solid var(--border-color);
   425→  border-radius: var(--border-radius-lg);
   426→  padding: 1.75rem;
   427→  transition: all var(--transition);
   428→}
   429→
   430→.landing__feature-card:hover {
   431→  border-color: var(--border-hover);
   432→  box-shadow: var(--shadow-glow);
   433→  transform: translateY(-4px);
   434→}
   435→
   436→.landing__feature-icon {
   437→  font-size: 2rem;
   438→  margin-bottom: 1rem;
   439→}
   440→
   441→.landing__feature-title {
   442→  font-size: 1.1rem;
   443→  margin-bottom: 0.75rem;
   444→}
   445→
   446→/* ========== CLIENT LOGOS ========== */
   447→.landing__clients {
   448→  padding: 3rem 0;
   449→  background: var(--bg-surface);
   450→  border-top: 1px solid var(--border-color);
   451→  border-bottom: 1px solid var(--border-color);
   452→}
   453→
   454→.landing__clients-label {
   455→  text-align: center;
   456→  font-size: 0.75rem;
   457→  font-weight: 700;
   458→  text-transform: uppercase;
   459→  letter-spacing: 0.14em;
   460→  color: var(--text-muted);
   461→  margin-bottom: 2rem;
   462→}
   463→
   464→.landing__clients-strip {
   465→  display: flex;
   466→  align-items: center;
   467→  justify-content: center;
   468→  gap: 3.5rem;
   469→  flex-wrap: wrap;
   470→}
   471→
   472→.landing__client-logo {
   473→  display: flex;
   474→  align-items: center;
   475→  opacity: 0.45;
   476→  transition: opacity 0.22s ease;
   477→  text-decoration: none;
   478→}
   479→
   480→.landing__client-logo:hover {
   481→  opacity: 0.85;
   482→}
   483→
   484→.landing__client-logo img {
   485→  height: 34px;
   486→  max-width: 130px;
   487→  object-fit: contain;
   488→  filter: brightness(0) invert(1);
   489→}
   490→
   491→.landing__client-name {
   492→  font-size: 1rem;
   493→  font-weight: 800;
   494→  color: var(--text-secondary);
   495→  letter-spacing: -0.02em;
   496→  white-space: nowrap;
   497→}
   498→
   499→/* ========== TESTIMONIALS ========== */
   500→.landing__testimonial {
   501→  background: var(--bg-card);
   502→  border: 1px solid var(--border-color);
   503→  border-radius: var(--border-radius-lg);
   504→  padding: 1.75rem;
   505→  display: flex;
   506→  flex-direction: column;
   507→  gap: 1rem;
   508→  transition: all var(--transition);
   509→}
   510→
   511→.landing__testimonial:hover {
   512→  border-color: var(--border-hover);
   513→  box-shadow: var(--shadow-glow);
   514→}
   515→
   516→.landing__testimonial-stars { color: #f59e0b; font-size: 1rem; }
   517→
   518→.landing__testimonial-text {
   519→  font-size: 0.925rem;
   520→  line-height: 1.7;
   521→  color: var(--text-secondary);
   522→  font-style: italic;
   523→  flex: 1;
   524→}
   525→
   526→.landing__testimonial-author {
   527→  display: flex;
   528→  align-items: center;
   529→  gap: 0.75rem;
   530→}
   531→
   532→.landing__testimonial-avatar {
   533→  width: 36px; height: 36px;
   534→  border-radius: 50%;
   535→  background: var(--gradient-primary);
   536→  display: flex;
   537→  align-items: center;
   538→  justify-content: center;
   539→  font-weight: 700;
   540→  font-size: 0.875rem;
   541→  color: white;
   542→  flex-shrink: 0;
   543→}
   544→
   545→.landing__testimonial-author strong {
   546→  display: block;
   547→  font-size: 0.875rem;
   548→  color: var(--text-primary);
   549→}
   550→
   551→.landing__testimonial-author small {
   552→  font-size: 0.775rem;
   553→  color: var(--text-muted);
   554→}
   555→
   556→/* ========== CTA ========== */
   557→.landing__cta-card {
   558→  position: relative;
   559→  text-align: center;
   560→  background: var(--bg-surface);
   561→  border: 1px solid rgba(99,102,241,0.2);
   562→  border-radius: var(--border-radius-xl);
   563→  padding: 5rem 3rem;
   564→  overflow: hidden;
   565→}
   566→
   567→.landing__cta-orb {
   568→  position: absolute;
   569→  width: 500px; height: 500px;
   570→  background: radial-gradient(circle, rgba(99,102,241,0.15), transparent 70%);
   571→  border-radius: 50%;
   572→  top: 50%; left: 50%;
   573→  transform: translate(-50%, -50%);
   574→  pointer-events: none;
   575→}
   576→
   577→.landing__cta-title {
   578→  font-size: clamp(1.75rem, 4vw, 3rem);
   579→  margin-bottom: 1.5rem;
   580→  font-weight: 900;
   581→}
   582→
   583→.landing__cta-card > p {
   584→  font-size: 1.05rem;
   585→  max-width: 500px;
   586→  margin: 0 auto 2.5rem;
   587→}
   588→
   589→.landing__cta-actions {
   590→  display: flex;
   591→  gap: 1rem;
   592→  justify-content: center;
   593→  flex-wrap: wrap;
   594→  margin-bottom: 1.5rem;
   595→}
   596→
   597→.landing__cta-note {
   598→  color: var(--text-muted);
   599→  font-size: 0.82rem;
   600→}
   601→
   602→/* ========== N8N ADD-ON BLOCK ========== */
   603→.landing__addon-block {
   604→  display: flex;
   605→  align-items: center;
   606→  justify-content: space-between;
   607→  gap: 2rem;
   608→  background: linear-gradient(135deg, rgba(99,102,241,0.07), rgba(139,92,246,0.04));
   609→  border: 1px solid rgba(99,102,241,0.3);
   610→  border-radius: var(--border-radius-xl);
   611→  padding: 2rem 2.5rem;
   612→  margin-top: 1.5rem;
   613→}
   614→
   615→.landing__addon-badge { margin-bottom: 0.75rem; }
   616→
   617→.landing__addon-title {
   618→  font-size: 1.35rem;
   619→  font-weight: 800;
   620→  color: var(--text-primary);
   621→  margin-bottom: 0.4rem;
   622→}
   623→
   624→.landing__addon-desc {
   625→  font-size: 0.9rem;
   626→  color: var(--text-secondary);
   627→  max-width: 420px;
   628→  margin-bottom: 1rem;
   629→}
   630→
   631→.landing__addon-features {
   632→  list-style: none;
   633→  padding: 0;
   634→  margin: 0;
   635→  display: flex;
   636→  flex-direction: column;
   637→  gap: 0.35rem;
   638→}
   639→
   640→.landing__addon-features li {
   641→  font-size: 0.85rem;
   642→  color: var(--text-secondary);
   643→}
   644→
   645→.landing__addon-right {
   646→  display: flex;
   647→  flex-direction: column;
   648→  align-items: center;
   649→  gap: 0.6rem;
   650→  flex-shrink: 0;
   651→  min-width: 180px;
   652→  text-align: center;
   653→}
   654→
   655→.landing__addon-price {
   656→  display: flex;
   657→  align-items: baseline;
   658→  gap: 0.3rem;
   659→}
   660→
   661→.landing__addon-amount {
   662→  font-size: 2.4rem;
   663→  font-weight: 900;
   664→  background: linear-gradient(135deg, #6366f1, #a78bfa);
   665→  -webkit-background-clip: text;
   666→  -webkit-text-fill-color: transparent;
   667→  background-clip: text;
   668→}
   669→
   670→.landing__addon-period {
   671→  font-size: 0.9rem;
   672→  color: var(--text-muted);
   673→}
   674→
   675→.landing__addon-renew {
   676→  font-size: 0.75rem;
   677→  color: var(--text-muted);
   678→  margin: 0;
   679→}
